const r = $('Compute KPIs').first().json.report || {};
const score = r.health_score;
const color = r.health_color || 'gray';
const bg = color === 'green' ? '#10b981' : (color === 'yellow' ? '#f59e0b' : '#dc2626');
const tops = r.top_projects_by_activity || [];
const topsHtml = tops.length>0 ? tops.map(t => '<li>'+t.name+' — <b>'+t.events+'</b> eventos</li>').join('') : '<li><i>sin actividad reciente</i></li>';
const card = (label, value, unit) => '<td style="padding:14px;background:#f9fafb;border-radius:6px;width:33%;vertical-align:top"><div style="font-size:11px;color:#6b7280;text-transform:uppercase">'+label+'</div><div style="font-size:22px;font-weight:bold;color:#1f2937;margin-top:4px">'+(value!=null?value:'-')+(unit?' <span style="font-size:13px;color:#6b7280;font-weight:normal">'+unit+'</span>':'')+'</div></td>';
const html = '<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;padding:20px;color:#1f2937">' +
'<h1 style="color:#0f172a;margin:0 0 4px">Resumen semanal estudio</h1>' +
'<div style="color:#64748b;font-size:13px;margin-bottom:16px">Lunes ' + new Date().toLocaleDateString('es-ES') + ' — datos ultimos 7 dias</div>' +
'<div style="background:'+bg+';color:white;padding:14px 20px;border-radius:8px;margin-bottom:20px;display:flex;align-items:center;gap:14px"><div style="font-size:36px;font-weight:bold">'+(score!=null?score:'?')+'</div><div><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;opacity:.85">System health score</div><div style="font-size:14px;font-weight:600">'+color.toUpperCase()+'</div></div></div>' +
'<table style="width:100%;border-spacing:8px;border-collapse:separate">' +
  '<tr>' + card('Proyectos activos', r.projects_active||0) + card('Completados 7d', r.projects_completed_7d||0) + card('Cobrado 7d', Number(r.invoices_paid_7d_eur||0).toLocaleString('es-ES'), 'EUR') + '</tr>' +
  '<tr>' + card('Aftercare urgent', r.aftercare_open_urgent||0) + card('Collab overdue', r.collab_overdue||0) + card('Contratos expiran 7d', r.contracts_expiring_7d||0) + '</tr>' +
  '<tr>' + card('Consultas pending', r.consultations_pending||0) + card('LLM coste 7d', r.llm_cost_7d_usd||0, 'USD') + card('LLM calls 7d', r.llm_calls_7d||0) + '</tr>' +
'</table>' +
'<h2 style="color:#374151;font-size:16px;margin:24px 0 8px">Proyectos con mas actividad esta semana</h2>' +
'<ul style="color:#374151;font-size:14px">' + topsHtml + '</ul>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;border-top:1px solid #e5e7eb;padding-top:12px">Para detalle: <a href="https://n8n-n8n.zzeluw.easypanel.host/webhook/admin-index" style="color:#2563eb">/webhook/admin-index</a> con tu X-API-Key. Este email se envia automaticamente cada lunes a las 08:00.</p>' +
'</div>';
return [{ json: { html: html, subject: '[ArquitAI] Resumen semanal '+new Date().toLocaleDateString('es-ES')+' — score '+(score||'?')+' '+color.toUpperCase() } }];
